42: NS_IMETHODIMP
43: nsObserverService::CollectReports(nsIHandleReportCallback* aHandleReport,
44:                                   nsISupports* aData, bool aAnonymize) {
45:   struct SuspectObserver {
46:     SuspectObserver(const char* aTopic, size_t aReferentCount)
47:         : mTopic(aTopic), mReferentCount(aReferentCount) {}
48:     const char* mTopic;
49:     size_t mReferentCount;
50:   };
51: 
52:   size_t totalNumStrong = 0;
53:   size_t totalNumWeakAlive = 0;
54:   size_t totalNumWeakDead = 0;
55:   nsTArray<SuspectObserver> suspectObservers;
56: 
57:   for (auto iter = mObserverTopicTable.Iter(); !iter.Done(); iter.Next()) {
58:     nsObserverList* observerList = iter.Get();
59:     if (!observerList) {
60:       continue;
61:     }
62: 
63:     size_t topicNumStrong = 0;
64:     size_t topicNumWeakAlive = 0;
65:     size_t topicNumWeakDead = 0;
66: 
67:     nsMaybeWeakPtrArray<nsIObserver>& observers = observerList->mObservers;
68:     for (uint32_t i = 0; i < observers.Length(); i++) {
69:       if (observers[i].IsWeak()) {
70:         nsCOMPtr<nsIObserver> ref = observers[i].GetValue();
71:         if (ref) {
72:           topicNumWeakAlive++;
73:         } else {
74:           topicNumWeakDead++;
75:         }
76:       } else {
77:         topicNumStrong++;
78:       }
79:     }
80: 
81:     totalNumStrong += topicNumStrong;
82:     totalNumWeakAlive += topicNumWeakAlive;
83:     totalNumWeakDead += topicNumWeakDead;
84: 
85:     // Keep track of topics that have a suspiciously large number
86:     // of referents (symptom of leaks).
87:     size_t topicTotal = topicNumStrong + topicNumWeakAlive + topicNumWeakDead;
88:     if (topicTotal > kSuspectReferentCount) {
89:       SuspectObserver suspect(observerList->GetKey(), topicTotal);
90:       suspectObservers.AppendElement(suspect);
91:     }
92:   }
93: 
94:   // These aren't privacy-sensitive and so don't need anonymizing.
95:   for (uint32_t i = 0; i < suspectObservers.Length(); i++) {
96:     SuspectObserver& suspect = suspectObservers[i];
97:     nsPrintfCString suspectPath("observer-service-suspect/referent(topic=%s)",
98:                                 suspect.mTopic);
99:     aHandleReport->Callback(
100:         /* process */ ""_ns, suspectPath, KIND_OTHER, UNITS_COUNT,
101:         suspect.mReferentCount,
102:         nsLiteralCString("A topic with a suspiciously large number of "
103:                          "referents.  This may be symptomatic of a leak "
104:                          "if the number of referents is high with "
105:                          "respect to the number of windows."),
106:         aData);
107:   }
108: 
109:   MOZ_COLLECT_REPORT(
110:       "observer-service/referent/strong", KIND_OTHER, UNITS_COUNT,
111:       totalNumStrong,
112:       "The number of strong references held by the observer service.");
113: 
114:   MOZ_COLLECT_REPORT(
115:       "observer-service/referent/weak/alive", KIND_OTHER, UNITS_COUNT,
116:       totalNumWeakAlive,
117:       "The number of weak references held by the observer service that are "
118:       "still alive.");
119: 
120:   MOZ_COLLECT_REPORT(
121:       "observer-service/referent/weak/dead", KIND_OTHER, UNITS_COUNT,
122:       totalNumWeakDead,
123:       "The number of weak references held by the observer service that are "
124:       "dead.");
125: 
126:   return NS_OK;
127: }
